    class MarkupUtils:
        @staticmethod
        def validate(markup):
            """Stub: validate Pango markup. Returns empty string (valid) on iOS."""
            return ""

        @staticmethod
        def text2svg(text, font=None, slant='NORMAL', weight='NORMAL', size=1,
                     _placeholder=None, disable_liga=False, file_name='',
                     START_X=0, START_Y=0, width=600, height=400, *,
                     justify=None, indent=None, line_spacing=None,
                     alignment=None, pango_width=None):
            """Stub MarkupUtils.text2svg — renders markup as plain SVG text."""
            import re, os
            plain = re.sub(r'<[^>]+>', '', str(text))
            fs = max(size * 10, 12)
            esc = plain.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
            svg = (f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}">'
                   f'<text x="{START_X}" y="{START_Y + int(fs)}" '
                   f'font-family="{font or "Helvetica"}" '
                   f'font-size="{int(fs)}" fill="white">{esc}</text></svg>')
            if file_name:
                os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
                with open(str(file_name), 'w') as f:
                    f.write(svg)
                return str(file_name)
            return svg

